// ─── DOWNLOAD ─────────────────────────────────────────────────────────────────
// Caption is already baked into the image from fal.ai, so we just download clean

async function downloadAsPng(stickerUrl, addWatermark) {
  const SIZE   = 800;
  const canvas = document.createElement("canvas");
  canvas.width = SIZE; canvas.height = SIZE;
  const ctx    = canvas.getContext("2d");

  if (stickerUrl) {
    await new Promise(resolve => {
      const img = new Image(); img.crossOrigin = "anonymous";
      img.onload = () => { ctx.drawImage(img,0,0,SIZE,SIZE); resolve(); };
      img.onerror = resolve; img.src = stickerUrl;
    });
  }

  if (addWatermark) {
    ctx.font         = "bold 14px 'DynaPuff', cursive";
    ctx.fillStyle    = "rgba(255,255,255,0.45)";
    ctx.textAlign    = "right";
    ctx.textBaseline = "bottom";
    ctx.fillText(APP_DOMAIN, SIZE-10, SIZE-8);
  }

  const a = document.createElement("a");
  a.href = canvas.toDataURL("image/png");
  a.download = "cutepaw-sticker.png";
  a.click();
}

// ─── HOOKS ────────────────────────────────────────────────────────────────────

function useCredits() {
  const [cycleStart, setCycleStart]     = useState(()=>Date.now());
  const [credits, setCredits]           = useState(FREE_CREDITS);
  const [bonusCredits, setBonusCredits] = useState(0);
  const [isPro, setIsPro]               = useState(false);
  const [daysUntilReset, setDaysUntilReset] = useState(30);

  useEffect(()=>{
    const THIRTY = 30*24*60*60*1000;
    const tick = ()=>{
      const elapsed = Date.now()-cycleStart;
      setDaysUntilReset(Math.ceil(Math.max(0,THIRTY-elapsed)/(24*60*60*1000)));
      if (elapsed>=THIRTY&&!isPro){ setCycleStart(Date.now()); setCredits(FREE_CREDITS); }
    };
    tick(); const id=setInterval(tick,5000); return()=>clearInterval(id);
  },[cycleStart,isPro]);

  const spend      = useCallback(()=>{ if(isPro)return true; if(credits>0){setCredits(c=>c-1);return true;} if(bonusCredits>0){setBonusCredits(b=>b-1);return true;} return false; },[credits,bonusCredits,isPro]);
  const addCredits = useCallback(n=>setBonusCredits(b=>b+n),[]);
  const activatePro= useCallback(()=>setIsPro(true),[]);
  const total      = credits+bonusCredits;
  return { credits, bonusCredits, total, isPro, daysUntilReset, spend, addCredits, activatePro };
}

function useGallery() {
  const [items, setItems] = useState([]);
  const save   = useCallback(entry=>setItems(p=>[{...entry,id:Date.now(),savedAt:new Date().toLocaleDateString()},...p].slice(0,20)),[]);
  const remove = useCallback(id=>setItems(p=>p.filter(i=>i.id!==id)),[]);
  return { items, save, remove };
}

function useOrderForm() {
  const empty = {name:"",email:"",address:"",postcode:"",city:""};
  const [fields,setFields]   = useState(empty);
  const [touched,setTouched] = useState({});
  const [errors,setErrors]   = useState({});
  const validate = f=>{
    const e={};
    if(!f.name.trim())e.name="Required";
    if(!f.email.trim()||!/\S+@\S+\.\S+/.test(f.email))e.email="Valid email required";
    if(!f.address.trim())e.address="Required";
    if(!f.postcode.trim())e.postcode="Required";
    if(!f.city.trim())e.city="Required";
    return e;
  };
  const set      = (k,v)=>{const n={...fields,[k]:v};setFields(n);if(touched[k])setErrors(validate(n));};
  const touch    = k=>{setTouched(p=>({...p,[k]:true}));setErrors(validate(fields));};
  const touchAll = ()=>{setTouched(Object.keys(empty).reduce((a,k)=>({...a,[k]:true}),{}));setErrors(validate(fields));};
  return {fields,errors,touched,set,touch,touchAll,isValid:Object.keys(validate(fields)).length===0};
}

// ─── ONBOARDING SCREEN ────────────────────────────────────────────────────────

function OnboardingScreen({ onStart }) {
  const [stages, setStages] = useState([0, 1, 2, 0]);
  const [tick,   setTick]   = useState(0);

  useEffect(() => {
    const t = setInterval(() => setTick(n => n + 1), 1700);
    return () => clearInterval(t);
  }, []);

  useEffect(() => {
    setStages(prev => prev.map((s, i) => (tick + i) % 3));
  }, [tick]);

  const STAGE_LABELS  = ["PHOTO", "STICKER", "PRODUCT"];
  const STAGE_COLORS  = ["rgba(255,255,255,0.7)", "#FF85A1", "#4CB87A"];
  const STAGE_BORDERS = ["rgba(255,255,255,0.2)", "rgba(255,133,161,0.6)", "rgba(76,184,122,0.55)"];
  const STAGE_BGS     = ["rgba(255,255,255,0.06)", "rgba(255,133,161,0.1)", "rgba(76,184,122,0.08)"];

  const imgFor = (pet, stage) => {
    if (stage === 0) return ASSETS[`photo_${pet.id}`];
    if (stage === 1) return ASSETS[`sticker_${pet.id}`];
    return ASSETS[`product_${pet.id}`];
  };

  return (
    <div style={{...S.app, display:"flex", flexDirection:"column", alignItems:"center",
      justifyContent:"center", padding:"28px 16px 36px", textAlign:"center", minHeight:"100vh"}}>

      <div style={{fontSize:40, marginBottom:2}}>{APP_EMOJI}</div>
      <h1 style={{fontFamily:"'Rubik Bubbles',cursive", fontSize:26, color:"#fff", margin:"0 0 5px", lineHeight:1.2}}>
        Turn your pet into<br/>a sticker! 🎨
      </h1>
      <p style={{color:"rgba(255,255,255,0.4)", fontSize:12, fontFamily:"'DynaPuff',cursive",
        lineHeight:1.5, maxWidth:260, margin:"0 0 20px"}}>
        Photo → cartoon sticker → printed on anything. Under a minute.
      </p>

      {/* 4 mini cards in a row */}
      <div style={{display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:8,
        width:"100%", maxWidth:360, marginBottom:10}}>
        {ONBOARDING_PETS.map((pet, i) => {
          const stage = stages[i];
          const src   = imgFor(pet, stage);
          return (
            <div key={pet.id} style={{display:"flex", flexDirection:"column", gap:4}}>
              <div style={{
                position:"relative", borderRadius:12, overflow:"hidden", aspectRatio:"1/1",
                border:`2px solid ${STAGE_BORDERS[stage]}`,
                background: STAGE_BGS[stage],
                transition:"border-color 0.5s, background 0.5s",
                boxShadow: stage===1 ? "0 4px 14px rgba(255,133,161,0.3)"
                         : stage===2 ? "0 4px 14px rgba(76,184,122,0.25)" : "none",
              }}>
                <img src={src} alt={pet.id}
                  style={{width:"100%", height:"100%", objectFit:"cover",
                    transition:"opacity 0.4s ease"}} />
                {/* coloured dot top-right */}
                <div style={{position:"absolute", top:4, right:4, width:6, height:6,
                  borderRadius:"50%", background:STAGE_COLORS[stage],
                  boxShadow:`0 0 5px ${STAGE_COLORS[stage]}`}} />
              </div>
              <div style={{fontSize:7, fontWeight:700, fontFamily:"'DynaPuff',cursive",
                letterSpacing:"0.06em", color:STAGE_COLORS[stage], transition:"color 0.5s",
                textAlign:"center", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis"}}>
                {STAGE_LABELS[stage]}
              </div>
            </div>
          );
        })}
      </div>

      {/* Legend */}
      <div style={{display:"flex", alignItems:"center", gap:6, marginBottom:20}}>
        {STAGE_LABELS.map((l,i) => (
          <div key={i} style={{display:"flex", alignItems:"center", gap:4}}>
            <div style={{width:7, height:7, borderRadius:"50%", background:STAGE_COLORS[i]}} />
            <span style={{fontSize:9, color:"rgba(255,255,255,0.35)", fontFamily:"'DynaPuff',cursive"}}>{l}</span>
            {i < 2 && <span style={{color:"rgba(255,255,255,0.15)", fontSize:10, margin:"0 1px"}}>→</span>}
          </div>
        ))}
      </div>

      {/* Feature pills */}
      <div style={{display:"flex", gap:6, flexWrap:"wrap", justifyContent:"center", marginBottom:22, maxWidth:320}}>
        {["🎨 3 art styles","✍️ Funny captions","📦 Print on anything","🐾 Die-cut","⚡ 20 sec"].map((t,i)=>(
          <div key={i} style={{padding:"4px 9px", borderRadius:20,
            background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.1)",
            fontSize:10, color:"rgba(255,255,255,0.55)", fontFamily:"'DynaPuff',cursive"}}>
            {t}
          </div>
        ))}
      </div>

      <button onClick={onStart} style={{...S.btnPrimary, width:"100%", maxWidth:320,
        fontSize:17, padding:"15px 20px", boxShadow:"0 12px 32px rgba(255,133,161,0.5)"}}>
        Make my pet a sticker 🐾
      </button>
      <div style={{marginTop:10, color:"rgba(255,255,255,0.22)", fontSize:11,
        fontFamily:"'DynaPuff',cursive"}}>
        3 free stickers · No sign up needed
      </div>
      <style>{CSS}</style>
    </div>
  );
}

