// StickerCard — no caption overlay since it's baked into the image
function StickerCard({ url, style, size=200, onClick, showZoomHint, loading }) {
  const cardBg    = style ? style.bg : CHECKER;
  const hasBorder = !!style;
  return (
    <div onClick={onClick} style={{position:"relative",cursor:onClick?"pointer":"default",width:size,height:size,flexShrink:0}}>
      <div style={{position:"absolute",inset:0,borderRadius:size*0.12,background:cardBg,border:hasBorder?`2.5px solid ${style.border}`:"none",overflow:"hidden",boxShadow:hasBorder?`0 4px 16px ${style.shadow}`:"none",transition:"all 0.3s"}}>
        {loading
          ? <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:8}}>
              <div style={{width:32,height:32,borderRadius:"50%",border:"3px solid rgba(255,133,161,0.2)",borderTop:"3px solid #FF85A1",animation:"spin 1s linear infinite"}} />
              <span style={{fontSize:10,color:"rgba(255,255,255,0.3)",fontFamily:"'DynaPuff',cursive"}}>Drawing...</span>
            </div>
          : url
            ? <img src={url} alt="sticker" style={{width:"100%",height:"100%",objectFit:"contain"}} />
            : <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*0.3,color:"rgba(255,255,255,0.15)"}}>🐾</div>
        }
      </div>
      {showZoomHint&&!loading&&url&&(
        <div style={{position:"absolute",bottom:8,right:6,background:"rgba(0,0,0,0.5)",borderRadius:8,padding:"2px 7px",display:"flex",alignItems:"center",gap:3,pointerEvents:"none"}}>
          <span style={{fontSize:10}}>🔍</span>
          <span style={{fontSize:9,color:"rgba(255,255,255,0.75)",fontFamily:"'DynaPuff',cursive",fontWeight:700}}>Tap to zoom</span>
        </div>
      )}
    </div>
  );
}

function LoadingOverlay({ stage, progress }) {
  const MSGS = {
    analyzing:  ["Looking at your pet... 🔍","Reading those features...","Getting the vibe..."],
    generating: ["Drawing 3 styles at once... 🎨","Adding the outlines...","Nearly there!"],
    regen:      ["Trying again... 🔄","One more take...","Almost there!"],
  };
  const lines = MSGS[stage]||MSGS.analyzing;
  const [idx,setIdx] = useState(0);
  useEffect(()=>{const t=setInterval(()=>setIdx(i=>(i+1)%lines.length),1800);return()=>clearInterval(t);},[stage]);
  return (
    <div style={{position:"fixed",inset:0,zIndex:300,background:"rgba(10,5,28,0.94)",backdropFilter:"blur(16px)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:24}}>
      <div style={{position:"relative",width:80,height:80}}>
        <div style={{position:"absolute",inset:0,borderRadius:"50%",border:"3px solid rgba(255,133,161,0.15)",borderTop:"3px solid #FF85A1",animation:"spin 1s linear infinite"}} />
        <div style={{position:"absolute",inset:8,borderRadius:"50%",border:"3px solid rgba(123,97,255,0.15)",borderBottom:"3px solid #7B61FF",animation:"spin 1.4s linear infinite reverse"}} />
        <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:30}}>{APP_EMOJI}</div>
      </div>
      <div style={{textAlign:"center",width:"100%",maxWidth:280,padding:"0 20px"}}>
        <div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:20,color:"#fff",marginBottom:6}}>{lines[idx]}</div>
        <div style={{color:"rgba(255,255,255,0.35)",fontSize:12,fontFamily:"'DynaPuff',cursive",marginBottom:stage==="regen"?0:14}}>
          {stage==="generating"?"Generating 3 styles — about 20 seconds...":stage==="regen"?"About 15 seconds...":"Just a moment..."}
        </div>
        {stage!=="regen"&&(
          <>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
              <span style={{fontSize:10,color:"rgba(255,255,255,0.3)",fontFamily:"'DynaPuff',cursive"}}>{stage==="analyzing"?"Reading your pet...":"Drawing 3 styles..."}</span>
              <span style={{fontSize:10,color:"rgba(255,133,161,0.7)",fontFamily:"'DynaPuff',cursive",fontWeight:700}}>{progress}%</span>
            </div>
            <div style={{height:5,borderRadius:3,background:"rgba(255,255,255,0.08)",overflow:"hidden"}}>
              <div style={{height:"100%",borderRadius:3,background:"linear-gradient(90deg,#FF85A1,#7B61FF)",width:`${progress}%`,transition:"width 0.6s ease"}} />
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ─── REFERRAL MODAL ───────────────────────────────────────────────────────────

function ReferralModal({ deviceId, onClose, onClaim }) {
  const [copied, setCopied]   = useState(false);
  const [claimed, setClaimed] = useState(false);
  const link = `https://${APP_DOMAIN}/?ref=${deviceId || "friend"}`;

  const copyLink = async () => {
    try { await navigator.clipboard.writeText(link); } catch {}
    setCopied(true); setTimeout(()=>setCopied(false), 2500);
  };

  const shareLink = async () => {
    const msg = `Turn your pet into a cartoon sticker! 🐾 Try it free → ${link}`;
    if (navigator.share) { try { await navigator.share({text:msg}); pixels.referralShared(); return; } catch {} }
    await copyLink();
    pixels.referralShared();
  };

  // Referral credit is awarded server-side when the friend opens the link
  // The share button just tracks the share action — no instant credit
  const handleShare = () => {
    setClaimed(true);
    setTimeout(onClose, 1600);
  };

  return (
    <div style={S.overlay} onClick={onClose}>
      <div style={S.sheet} onClick={e=>e.stopPropagation()}>
        <div style={S.sheetHandle} />
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <h3 style={{margin:0,fontFamily:"'Rubik Bubbles',cursive",fontSize:22,color:"#fff"}}>Get a free sticker 🎁</h3>
            <p style={{margin:"3px 0 0",fontSize:12,color:"rgba(255,255,255,0.38)",fontFamily:"'DynaPuff',cursive"}}>Share the app, earn 1 free credit</p>
          </div>
          <button onClick={onClose} style={S.closeBtn}>✕</button>
        </div>

        <div style={{background:"linear-gradient(135deg,rgba(255,133,161,0.12),rgba(123,97,255,0.08))",border:"1px solid rgba(255,133,161,0.2)",borderRadius:18,padding:18,marginBottom:18,textAlign:"center"}}>
          <div style={{fontSize:48,marginBottom:8}}>🐾 → 🎨</div>
          <div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:18,color:"#fff",marginBottom:6}}>Share with a friend</div>
          <div style={{color:"rgba(255,255,255,0.45)",fontSize:13,fontFamily:"'DynaPuff',cursive",lineHeight:1.45}}>Share your link below. When a friend opens it, you earn 1 free sticker credit. No sign-up needed on their end.</div>
        </div>

        {/* Link box */}
        <div style={{display:"flex",gap:8,marginBottom:12}}>
          <div style={{flex:1,padding:"10px 12px",borderRadius:11,background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.1)",fontSize:12,color:"rgba(255,255,255,0.45)",fontFamily:"'DynaPuff',cursive",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
            {link}
          </div>
          <button onClick={copyLink} style={{padding:"10px 14px",borderRadius:11,border:"1px solid rgba(255,255,255,0.15)",background:copied?"rgba(76,184,122,0.2)":"rgba(255,255,255,0.08)",color:copied?"#4CB87A":"rgba(255,255,255,0.7)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'DynaPuff',cursive",flexShrink:0,transition:"all 0.2s"}}>
            {copied?"✓ Copied!":"Copy"}
          </button>
        </div>

        <button onClick={()=>{ shareLink(); handleShare(); }} style={{...S.btnPrimary,width:"100%",marginBottom:10}}>
          {claimed?"✅ Link shared! Credit incoming 🐾":"📤 Share and earn 1 credit"}
        </button>

        {/* Share buttons */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          {[["wa","WhatsApp","#25D366","💬"],["tg","Telegram","#229ED9","✈️"]].map(([k,l,bg,ic])=>(
            <button key={k} onClick={()=>{
              const msg=`Turn your pet into a cartoon sticker! 🐾 Try it free → ${link}`;
              if(k==="wa") window.open(`https://wa.me/?text=${encodeURIComponent(msg)}`);
              if(k==="tg") window.open(`https://t.me/share/url?url=${encodeURIComponent(link)}&text=${encodeURIComponent(msg)}`);
              pixels.referralShared();
              handleShare();
            }} style={{padding:"10px",borderRadius:12,border:"none",background:bg,color:"#fff",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'DynaPuff',cursive",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              <span style={{fontSize:16}}>{ic}</span>{l}
            </button>
          ))}
        </div>

        <div style={{marginTop:12,textAlign:"center",fontSize:10,color:"rgba(255,255,255,0.2)",fontFamily:"'DynaPuff',cursive"}}>
          Credit lands when your friend opens the link · Share as many times as you like
        </div>
      </div>
    </div>
  );
}

// ─── PAYWALL MODAL ────────────────────────────────────────────────────────────

function PaywallModal({ trigger, daysUntilReset, onClose, onPurchase, onPro, onReferral }) {
  const [tab,setTab]             = useState(trigger==="pro"?"pro":"credits");
  const [selected,setSelected]   = useState("pack_15");
  const [purchased,setPurchased] = useState(null);
  const [proOn,setProOn]         = useState(false);
  return (
    <div style={S.overlay} onClick={onClose}>
      <div style={{...S.sheet,maxHeight:"90vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
        <div style={S.sheetHandle} />
        <div style={{textAlign:"center",marginBottom:20}}>
          {trigger==="out_of_credits"?(
            <>
              <div style={{fontSize:48,marginBottom:8}}>😿</div>
              <h3 style={S.sheetTitle}>No credits left!</h3>
              <p style={S.sheetSub}>Pick up some more to keep going</p>
              <p style={{color:"rgba(123,97,255,0.7)",fontSize:11,fontFamily:"'DynaPuff',cursive",margin:0}}>Free 3 come back in {daysUntilReset} day{daysUntilReset!==1?"s":""} ✨</p>
            </>
          ):(
            <>
              <div style={{fontSize:48,marginBottom:8}}>⚡</div>
              <h3 style={S.sheetTitle}>Unlock everything</h3>
              <p style={S.sheetSub}>Unlimited stickers and exclusive styles</p>
            </>
          )}
        </div>

        {/* Free option — referral */}
        <div onClick={()=>{onClose();onReferral();}} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",borderRadius:13,background:"rgba(76,184,122,0.08)",border:"1px solid rgba(76,184,122,0.28)",marginBottom:14,cursor:"pointer"}}>
          <span style={{fontSize:22}}>🎁</span>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,color:"#4CB87A",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>Share to earn 1 free credit</div>
            <div style={{color:"rgba(255,255,255,0.35)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Share the app link with a friend → free sticker</div>
          </div>
          <span style={{color:"#4CB87A",fontSize:14}}>→</span>
        </div>

        <div style={{display:"flex",background:"rgba(255,255,255,0.06)",borderRadius:12,padding:4,marginBottom:20,gap:4}}>
          {[{k:"credits",l:"💳 Buy Credits"},{k:"pro",l:"⚡ Go Pro"}].map(({k,l})=>(
            <button key={k} onClick={()=>setTab(k)} style={{flex:1,padding:"10px",borderRadius:10,border:"none",cursor:"pointer",fontWeight:700,fontSize:13,fontFamily:"'DynaPuff',cursive",transition:"all 0.2s",
              background:tab===k?"rgba(255,255,255,0.12)":"transparent",
              color:tab===k?"#fff":"rgba(255,255,255,0.4)"}}>
              {l}
            </button>
          ))}
        </div>

        {tab==="credits"&&(
          <>
            <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:20}}>
              {CREDIT_PACKS.map(pack=>(
                <div key={pack.id} onClick={()=>setSelected(pack.id)} style={{padding:"14px 16px",borderRadius:16,cursor:"pointer",transition:"all 0.2s",display:"flex",alignItems:"center",gap:14,position:"relative",overflow:"hidden",
                  background:selected===pack.id?"rgba(255,133,161,0.15)":"rgba(255,255,255,0.05)",
                  border:`2px solid ${selected===pack.id?"#FF85A1":"rgba(255,255,255,0.1)"}`}}>
                  {pack.badge&&<div style={{position:"absolute",top:0,right:0,background:pack.popular?"linear-gradient(135deg,#FF85A1,#FF5C8A)":"linear-gradient(135deg,#4CB87A,#3AA869)",padding:"3px 10px",fontSize:9,fontWeight:800,color:"#fff",fontFamily:"'DynaPuff',cursive",borderRadius:"0 0 0 10px"}}>{pack.badge}</div>}
                  <div style={{fontSize:30}}>🎨</div>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:800,color:"#fff",fontSize:15,fontFamily:"'DynaPuff',cursive"}}>{pack.credits} stickers</div>
                    <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>{pack.label} · ${(pack.price/pack.credits).toFixed(2)} each</div>
                  </div>
                  <div style={{fontWeight:800,fontSize:20,fontFamily:"'Rubik Bubbles',cursive",color:selected===pack.id?"#FF85A1":"#fff"}}>${pack.price}</div>
                </div>
              ))}
            </div>
            <button onClick={()=>{const p=CREDIT_PACKS.find(x=>x.id===selected);onPurchase(p);setPurchased(p);}} style={{...S.btnPrimary,width:"100%",marginBottom:10}}>
              Buy {CREDIT_PACKS.find(x=>x.id===selected)?.credits} stickers · ${CREDIT_PACKS.find(x=>x.id===selected)?.price}
            </button>
            {purchased&&(
              <div style={{background:"rgba(76,184,122,0.12)",border:"1px solid rgba(76,184,122,0.3)",borderRadius:12,padding:"10px 14px",marginBottom:8,display:"flex",gap:8,alignItems:"center"}}>
                <span style={{fontSize:18}}>✅</span>
                <div style={{flex:1}}><div style={{fontWeight:700,color:"#4CB87A",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>{purchased.credits} credits added!</div><div style={{color:"rgba(255,255,255,0.4)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Never expire</div></div>
                <button onClick={onClose} style={{background:"transparent",border:"none",color:"rgba(255,255,255,0.5)",cursor:"pointer",fontSize:13,fontFamily:"'DynaPuff',cursive",fontWeight:700}}>Done →</button>
              </div>
            )}
            <button onClick={()=>setTab("pro")} style={{width:"100%",padding:"12px",borderRadius:14,border:"1px solid rgba(123,97,255,0.4)",background:"transparent",color:"#A78BFA",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>Or get unlimited with Pro ⚡</button>
          </>
        )}

        {tab==="pro"&&(
          <>
            <div style={{background:"linear-gradient(135deg,rgba(123,97,255,0.15),rgba(91,65,223,0.1))",border:"1px solid rgba(123,97,255,0.3)",borderRadius:18,padding:18,marginBottom:20}}>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14}}>
                <span style={{fontSize:28}}>⚡</span>
                <div><div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:20,color:"#fff"}}>{APP_NAME} Pro</div><div style={{color:"rgba(255,255,255,0.45)",fontSize:12,fontFamily:"'DynaPuff',cursive"}}>Everything, unlimited</div></div>
                <div style={{marginLeft:"auto",textAlign:"right"}}><div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:24,color:"#A78BFA"}}>${PRO_PRICE}</div><div style={{color:"rgba(255,255,255,0.35)",fontSize:10,fontFamily:"'DynaPuff',cursive"}}>per month</div></div>
              </div>
              {[["🎨","Unlimited stickers","No credit limits, ever"],["⚡","3 exclusive Pro styles","Neon, Golden and Minimal"],["📥","No watermark on downloads","Clean PNGs, yours to keep"],["💾","Sticker gallery","Save and reuse all creations"],["🎁","Free sticker sheet monthly","Printed and posted to you"]].map(([ic,title,desc],i)=>(
                <div key={i} style={{display:"flex",gap:12,alignItems:"flex-start",marginBottom:i<4?12:0}}>
                  <span style={{fontSize:18,lineHeight:1}}>{ic}</span>
                  <div style={{flex:1}}><div style={{fontWeight:700,color:"#fff",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>{title}</div><div style={{color:"rgba(255,255,255,0.35)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>{desc}</div></div>
                  <span style={{color:"#4CB87A",fontSize:14}}>✓</span>
                </div>
              ))}
            </div>
            <button onClick={()=>{onPro();setProOn(true);}} style={{...S.btnPrimary,width:"100%",background:"linear-gradient(135deg,#7B61FF,#5B41DF)",boxShadow:"0 8px 24px rgba(123,97,255,0.45)",marginBottom:10}}>
              {proOn?"✅ You're on Pro!": `Start Pro · $${PRO_PRICE}/month`}
            </button>
            {proOn
              ? <div style={{textAlign:"center"}}><div style={{color:"#A78BFA",fontWeight:700,fontSize:13,fontFamily:"'DynaPuff',cursive",marginBottom:4}}>Let's go! ⚡</div><button onClick={onClose} style={{color:"rgba(255,255,255,0.5)",fontSize:12,fontFamily:"'DynaPuff',cursive",background:"transparent",border:"none",cursor:"pointer"}}>Start creating →</button></div>
              : <div style={{textAlign:"center",color:"rgba(255,255,255,0.25)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Cancel any time. Billed monthly.</div>
            }
          </>
        )}
      </div>
    </div>
  );
}

// ─── GALLERY MODAL ────────────────────────────────────────────────────────────

function GalleryModal({ items, onClose, onDelete, onUse }) {
  return (
    <div style={S.overlay} onClick={onClose}>
      <div style={{...S.sheet,maxHeight:"85vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
        <div style={S.sheetHandle} />
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div><h3 style={{margin:0,fontFamily:"'Rubik Bubbles',cursive",fontSize:22,color:"#fff"}}>My Gallery 🖼️</h3><p style={{margin:"3px 0 0",fontSize:12,color:"rgba(255,255,255,0.38)",fontFamily:"'DynaPuff',cursive"}}>{items.length} saved</p></div>
          <button onClick={onClose} style={S.closeBtn}>✕</button>
        </div>
        {items.length===0
          ? <div style={{textAlign:"center",padding:"40px 20px"}}><div style={{fontSize:48,marginBottom:12}}>🐾</div><div style={{fontFamily:"'DynaPuff',cursive",color:"rgba(255,255,255,0.4)",fontSize:14}}>No stickers saved yet</div></div>
          : <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              {items.map(item=>(
                <div key={item.id} style={{background:"rgba(255,255,255,0.05)",borderRadius:18,padding:12,border:"1px solid rgba(255,255,255,0.08)",display:"flex",flexDirection:"column",alignItems:"center",gap:8,position:"relative"}}>
                  <button onClick={()=>onDelete(item.id)} style={{position:"absolute",top:8,right:8,background:"rgba(255,80,80,0.15)",border:"none",borderRadius:"50%",width:22,height:22,color:"rgba(255,120,120,0.7)",fontSize:11,cursor:"pointer"}}>✕</button>
                  <StickerCard url={item.url} style={ALL_STYLES.find(s=>s.id===item.styleId)||FREE_STYLES[0]} size={110} />
                  <div style={{fontSize:9,color:"rgba(255,255,255,0.25)",fontFamily:"'DynaPuff',cursive"}}>{item.savedAt}</div>
                  <button onClick={()=>{onUse(item);onClose();}} style={{width:"100%",padding:"7px",borderRadius:10,border:"none",background:"linear-gradient(135deg,#FF85A1,#FF5C8A)",color:"#fff",fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>Use this →</button>
                </div>
              ))}
            </div>
        }
      </div>
    </div>
  );
}

// ─── PRODUCT MOCKUP MODAL ─────────────────────────────────────────────────────

function MockupModal({ product, stickerUrl, onClose }) {
  const Img = ({w=70,h=70,style={}}) => <div style={{width:w,height:h,flexShrink:0,...style}}>{stickerUrl&&<img src={stickerUrl} alt="" style={{width:"100%",height:"100%",objectFit:"contain"}} />}</div>;
  const renderMockup = () => {
    switch(product.id){
      case "physsticker": return <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,padding:"20px 0"}}>{[-8,0,8].map((r,i)=><div key={i} style={{width:80,height:80,transform:`rotate(${r}deg)`,filter:"drop-shadow(0 4px 12px rgba(0,0,0,0.4))"}}>{stickerUrl&&<img src={stickerUrl} alt="" style={{width:"100%",height:"100%",objectFit:"contain"}} />}</div>)}</div>;
      case "tshirt": return <div style={{position:"relative",width:200,height:220,margin:"0 auto"}}><div style={{position:"absolute",inset:0,background:"linear-gradient(180deg,#f0e8df,#e0d0c2)",borderRadius:"0 0 30px 30px",clipPath:"polygon(15% 0%,85% 0%,100% 15%,90% 15%,90% 100%,10% 100%,10% 15%,0% 15%)"}} /><div style={{position:"absolute",top:"2%",left:"8%",width:"20%",height:"18%",background:"#e0d0c2",borderRadius:"50% 50% 0 0"}} /><div style={{position:"absolute",top:"2%",right:"8%",width:"20%",height:"18%",background:"#e0d0c2",borderRadius:"50% 50% 0 0"}} /><Img w={70} h={70} style={{position:"absolute",top:"18%",left:"50%",transform:"translateX(-50%)"}} /></div>;
      case "mug": return <div style={{position:"relative",width:180,height:160,margin:"0 auto"}}><div style={{position:"absolute",left:10,top:10,width:145,height:140,background:"linear-gradient(135deg,#f8f8f8,#e0e0e0)",borderRadius:"8px 8px 24px 24px",boxShadow:"inset -8px 0 16px rgba(0,0,0,0.08),0 8px 24px rgba(0,0,0,0.2)"}} /><div style={{position:"absolute",right:0,top:30,width:28,height:60,borderRadius:"0 50% 50% 0",border:"5px solid #d0d0d0",borderLeft:"none"}} /><Img w={65} h={65} style={{position:"absolute",left:24,top:28}} /></div>;
      case "tote": return <div style={{position:"relative",width:180,height:200,margin:"0 auto"}}><div style={{position:"absolute",top:30,left:20,right:20,bottom:0,background:"linear-gradient(180deg,#d8c8a0,#c8b888)",borderRadius:"4px 4px 16px 16px",boxShadow:"0 8px 24px rgba(0,0,0,0.3)"}} /><div style={{position:"absolute",top:0,left:50,width:16,height:36,border:"5px solid #b8a870",borderBottom:"none",borderRadius:"8px 8px 0 0"}} /><div style={{position:"absolute",top:0,right:50,width:16,height:36,border:"5px solid #b8a870",borderBottom:"none",borderRadius:"8px 8px 0 0"}} /><Img w={70} h={70} style={{position:"absolute",top:60,left:"50%",transform:"translateX(-50%)"}} /></div>;
      case "phone": return <div style={{position:"relative",width:130,height:220,margin:"0 auto"}}><div style={{position:"absolute",inset:0,background:"linear-gradient(135deg,#2a2a3e,#1a1a2e)",borderRadius:28,boxShadow:"0 8px 32px rgba(0,0,0,0.5)"}} /><div style={{position:"absolute",top:10,left:"50%",transform:"translateX(-50%)",width:30,height:6,background:"rgba(255,255,255,0.15)",borderRadius:3}} /><div style={{position:"absolute",inset:18,top:28,background:"linear-gradient(135deg,#1a1030,#2a1060)",borderRadius:16,display:"flex",alignItems:"center",justifyContent:"center"}}><Img w={70} h={70} /></div></div>;
      case "pillow": return <div style={{position:"relative",width:200,height:200,margin:"0 auto"}}><div style={{position:"absolute",inset:0,background:"linear-gradient(135deg,#dce8f0,#c8d8e8)",borderRadius:30,boxShadow:"inset 0 0 40px rgba(0,0,0,0.12),0 8px 24px rgba(0,0,0,0.2)"}} /><div style={{position:"absolute",inset:12,border:"2px solid rgba(255,255,255,0.5)",borderRadius:22}} /><Img w={80} h={80} style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)"}} /></div>;
      case "poster": return <div style={{position:"relative",width:160,height:200,margin:"0 auto"}}><div style={{position:"absolute",inset:0,background:"linear-gradient(180deg,#f8f5ee,#f0ece0)",borderRadius:4,boxShadow:"0 8px 24px rgba(0,0,0,0.3)"}} /><div style={{position:"absolute",inset:12,border:"2px solid rgba(0,0,0,0.08)",borderRadius:2,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:8}}><Img w={90} h={90} /><div style={{fontSize:9,color:"rgba(0,0,0,0.25)",fontFamily:"'DynaPuff',cursive",fontWeight:700,letterSpacing:"0.1em"}}>MY PET</div></div></div>;
      case "notebook": return <div style={{position:"relative",width:150,height:200,margin:"0 auto"}}><div style={{position:"absolute",inset:0,background:"linear-gradient(135deg,#1a1a2e,#12122a)",borderRadius:"4px 12px 12px 4px",boxShadow:"0 8px 24px rgba(0,0,0,0.5)"}} /><div style={{position:"absolute",top:0,left:0,width:14,bottom:0,background:"rgba(255,255,255,0.06)",borderRadius:"4px 0 0 4px"}} />{[0.3,0.5,0.7].map(y=><div key={y} style={{position:"absolute",left:20,right:16,top:`${y*100}%`,height:1,background:"rgba(255,255,255,0.07)"}} />)}<Img w={75} h={75} style={{position:"absolute",top:"50%",left:"55%",transform:"translate(-50%,-50%)"}} /></div>;
      default: return <div style={{textAlign:"center",padding:"20px 0"}}><div style={{fontSize:80}}>{product.emoji}</div></div>;
    }
  };
  return (
    <div style={{...S.overlay,alignItems:"center"}} onClick={onClose}>
      <div style={{background:"linear-gradient(170deg,#1e1040,#16213e)",borderRadius:26,padding:24,width:"100%",maxWidth:360,margin:20,border:"1px solid rgba(255,255,255,0.12)"}} onClick={e=>e.stopPropagation()}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h3 style={{margin:0,fontFamily:"'Rubik Bubbles',cursive",fontSize:20,color:"#fff"}}>{product.emoji} {product.name}</h3><button onClick={onClose} style={S.closeBtn}>✕</button></div>
        <div style={{marginBottom:20}}>{renderMockup()}</div>
        <div style={{background:"rgba(255,133,161,0.08)",border:"1px solid rgba(255,133,161,0.2)",borderRadius:12,padding:"10px 14px",display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{color:"rgba(255,255,255,0.55)",fontSize:12,fontFamily:"'DynaPuff',cursive"}}>Ships in 5 to 7 days</span><span style={{color:"#FF85A1",fontWeight:800,fontSize:16,fontFamily:"'Rubik Bubbles',cursive"}}>${product.price}</span></div>
      </div>
    </div>
  );
}

// ─── DIGITAL MODAL ────────────────────────────────────────────────────────────

function DigitalModal({ stickerUrl, isPro, onClose }) {
  const [done,setDone]     = useState(false);
  const [busy,setBusy]     = useState(false);
  const [copied,setCopied] = useState(false);
  const handleDownload = async()=>{ setBusy(true); await downloadAsPng(stickerUrl,!isPro); setBusy(false); setDone(true); };
  const share = async p=>{
    const msg=`My pet is now a cartoon sticker! 🐾 ${APP_DOMAIN}`;
    if(p==="wa") window.open(`https://wa.me/?text=${encodeURIComponent(msg)}`);
    if(p==="tg") window.open(`https://t.me/share/url?url=${APP_DOMAIN}&text=${encodeURIComponent(msg)}`);
    if(p==="copy"){ try{await navigator.clipboard.writeText(msg);}catch{} setCopied(true); setTimeout(()=>setCopied(false),2000); }
  };
  return (
    <div style={S.overlay} onClick={onClose}>
      <div style={S.sheet} onClick={e=>e.stopPropagation()}>
        <div style={S.sheetHandle} />
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div><h3 style={{margin:0,fontFamily:"'Rubik Bubbles',cursive",fontSize:22,color:"#fff"}}>Digital Sticker ✨</h3><p style={{margin:"3px 0 0",fontSize:12,color:"rgba(255,255,255,0.38)",fontFamily:"'DynaPuff',cursive"}}>Save it and use it anywhere</p></div>
          <button onClick={onClose} style={S.closeBtn}>✕</button>
        </div>
        <div style={{display:"flex",justifyContent:"center",marginBottom:18}}>
          <StickerCard url={stickerUrl} size={160} />
        </div>
        {!isPro&&<div style={{background:"rgba(123,97,255,0.08)",border:"1px solid rgba(123,97,255,0.2)",borderRadius:12,padding:"8px 14px",marginBottom:12,fontSize:11,color:"rgba(200,180,255,0.7)",fontFamily:"'DynaPuff',cursive"}}>⚡ Free download has a small watermark. Go Pro to remove it.</div>}
        <button onClick={handleDownload} disabled={busy} style={{width:"100%",padding:"13px",borderRadius:13,border:"none",background:done?"rgba(76,184,122,0.8)":"linear-gradient(135deg,#7B61FF,#5B41DF)",color:"#fff",fontWeight:800,fontSize:14,cursor:busy?"default":"pointer",fontFamily:"'DynaPuff',cursive",boxShadow:"0 8px 24px rgba(123,97,255,0.4)",marginBottom:10}}>
          {done?"✅ Saved!":busy?"Saving...":"📥 Save PNG"}
        </button>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
          {[["wa","WhatsApp","#25D366","💬"],["tg","Telegram","#229ED9","✈️"],["copy",copied?"Copied!":"Copy link","rgba(255,255,255,0.08)","🔗"]].map(([k,l,bg,ic])=>(
            <button key={k} onClick={()=>share(k)} style={{padding:"10px 6px",borderRadius:12,border:"1px solid rgba(255,255,255,0.1)",background:bg,color:"#fff",fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"'DynaPuff',cursive",display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
              <span style={{fontSize:17}}>{ic}</span>{l}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── PHRASE EDITOR ────────────────────────────────────────────────────────────

function PhraseEditor({ phrases, selected, onSelect, custom, setCustom, fontId, setFontId, colorId, setColorId, onRegenerate }) {
  const [open,setOpen] = useState(false);
  return (
    <div style={{background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.09)",borderRadius:14,padding:14,marginBottom:14}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:open?12:0}}>
        <span style={{fontSize:12,fontWeight:600,color:"rgba(255,255,255,0.55)",fontFamily:"'DynaPuff',cursive"}}>✏️ Caption</span>
        <button onClick={()=>setOpen(o=>!o)} style={S.btnSmall}>{open?"Done":"Edit"}</button>
      </div>
      {!open&&<div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:15,color:"#fff",marginTop:8}}>"{custom||selected}"</div>}
      {open&&(
        <>
          <input type="text" value={custom} onChange={e=>setCustom(e.target.value)} placeholder={selected||"Write your own..."} maxLength={30} style={S.input} />
          <div style={{fontSize:10,color:"rgba(255,133,161,0.6)",fontFamily:"'DynaPuff',cursive",marginBottom:8,marginTop:-4}}>Caption is drawn into your sticker — tap Redraw after changing it</div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:10}}>
            {phrases.filter(Boolean).map((p,i)=>(
              <button key={i} onClick={()=>{onSelect(p);setCustom("");}} style={{...S.chip,background:selected===p&&!custom?"rgba(255,133,161,0.2)":"rgba(255,255,255,0.05)",borderColor:selected===p&&!custom?"#FF85A1":"rgba(255,255,255,0.1)",color:selected===p&&!custom?"#FF85A1":"rgba(255,255,255,0.55)"}}>
                {p}
              </button>
            ))}
          </div>
          <button onClick={onRegenerate} style={{...S.btnPrimary,width:"100%",padding:"10px",fontSize:12,marginBottom:12}}>🔄 Redraw sticker with this caption</button>
          <div style={{marginBottom:10}}>
            <div style={S.label}>FONT STYLE (preview)</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
              {PHRASE_FONTS.map(f=>(
                <button key={f.id} onClick={()=>setFontId(f.id)} style={{padding:"5px 10px",borderRadius:8,cursor:"pointer",fontFamily:f.css,fontWeight:700,fontSize:11,transition:"all 0.2s",
                  border:`1.5px solid ${fontId===f.id?"#FF85A1":"rgba(255,255,255,0.12)"}`,
                  background:fontId===f.id?"rgba(255,133,161,0.15)":"rgba(255,255,255,0.04)",
                  color:fontId===f.id?"#FF85A1":"rgba(255,255,255,0.55)"}}>
                  {f.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <div style={S.label}>TEXT COLOR (preview)</div>
            <div style={{display:"flex",gap:8}}>
              {PHRASE_COLORS.map(c=>(
                <button key={c.id} onClick={()=>setColorId(c.id)} title={c.label} style={{width:24,height:24,borderRadius:"50%",cursor:"pointer",background:c.hex,transition:"all 0.2s",border:colorId===c.id?"2.5px solid #fff":"2px solid rgba(255,255,255,0.15)",boxShadow:colorId===c.id?"0 0 0 2px rgba(255,255,255,0.3)":"none",transform:colorId===c.id?"scale(1.2)":"scale(1)"}} />
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// ─── STYLE PICKER ─────────────────────────────────────────────────────────────

function StylePicker({ styleUrls, selectedId, onSelect, isPro, onUnlock, loadingIds }) {
  return (
    <div style={{marginBottom:14}}>
      <div style={S.label}>STICKER STYLE — tap to switch instantly</div>
      <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-start"}}>
        {ALL_STYLES.map(st=>{
          const locked  = st.proOnly&&!isPro;
          const active  = selectedId===st.id;
          const url     = styleUrls[st.id];
          const loading = loadingIds.includes(st.id);
          return (
            <div key={st.id} onClick={()=>locked?onUnlock():onSelect(st.id)} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4,cursor:"pointer"}}>
              {/* Mini sticker preview thumbnail */}
              <div style={{width:54,height:54,borderRadius:12,overflow:"hidden",position:"relative",
                background:locked?"rgba(255,255,255,0.04)":st.bg,
                border:`2.5px solid ${active?st.border:"rgba(255,255,255,0.1)"}`,
                filter:locked?"grayscale(1) opacity(0.35)":"none",
                boxShadow:active?`0 4px 14px ${st.shadow}`:"none",
                transition:"all 0.2s"}}>
                {locked
                  ? <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>🔒</div>
                  : loading
                    ? <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{width:18,height:18,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.15)",borderTop:"2px solid #FF85A1",animation:"spin 0.8s linear infinite"}} /></div>
                    : url
                      ? <img src={url} alt={st.label} style={{width:"100%",height:"100%",objectFit:"contain"}} />
                      : <div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22}}>{st.emoji}</div>
                }
                {active&&!locked&&<div style={{position:"absolute",bottom:2,right:2,width:10,height:10,borderRadius:"50%",background:st.border,boxShadow:`0 0 6px ${st.border}`}} />}
              </div>
              <span style={{fontSize:8,fontWeight:700,fontFamily:"'DynaPuff',cursive",whiteSpace:"nowrap",color:active?st.border:"rgba(255,255,255,0.28)"}}>
                {st.label}{st.proOnly?" ⚡":""}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── EDIT STICKER BANNER (shown on steps 2 & 3) ──────────────────────────────

function EditStickerBanner({ url, style, onEdit }) {
  return (
    <div style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.09)",borderRadius:14,marginBottom:16}}>
      <StickerCard url={url} style={style} size={64} />
      <div style={{flex:1}}>
        <div style={{fontWeight:700,color:"#fff",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>Your sticker</div>
        <div style={{color:"rgba(255,255,255,0.35)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Caption, style and font</div>
      </div>
      <button onClick={onEdit} style={{padding:"7px 14px",borderRadius:10,border:"1px solid rgba(255,133,161,0.4)",background:"rgba(255,133,161,0.08)",color:"#FF85A1",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'DynaPuff',cursive",flexShrink:0}}>
        ✏️ Edit
      </button>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────

export default function App({ deviceId, serverCredits, onCreditsChanged }) {
  // Credits come from server via props (see main.jsx → useIdentity)
  const credits        = serverCredits?.free          ?? 0;
  const bonusCredits   = serverCredits?.bonus         ?? 0;
  const total          = serverCredits?.isPro ? Infinity : (serverCredits?.total ?? 0);
  const isPro          = serverCredits?.isPro         ?? false;
  const daysUntilReset = serverCredits?.daysUntilReset ?? 30;
  const addCredits     = useCallback(() => onCreditsChanged?.(), [onCreditsChanged]);
  const activatePro    = useCallback(() => onCreditsChanged?.(), [onCreditsChanged]);
  const gallery = useGallery();
  const form    = useOrderForm();

  // Onboarding
  const [showOnboarding, setShowOnboarding] = useState(true);

  // Navigation
  const [step, setStep]           = useState(0);
  const [orderDone, setOrderDone] = useState(false);

  // Upload / camera
  const [captureMode, setCaptureMode] = useState("upload");
  const [petImage, setPetImage]       = useState(null);
  const [petFile, setPetFile]         = useState(null);
  const [snapPreview, setSnapPreview] = useState(null);
  const [dragOver, setDragOver]       = useState(false);
  const fileRef   = useRef();
  const videoRef  = useRef();
  const streamRef = useRef(null);

  // Generation
  const [loadingStage, setLoadingStage]       = useState(null);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [regenLoading, setRegenLoading]       = useState(false);
  const [regenStyleIds, setRegenStyleIds]     = useState([]); // which styles are loading
  const [genError, setGenError]               = useState(null);

  // Sticker results — one URL per style
  const [styleUrls, setStyleUrls]           = useState({});  // { kawaii: url, comic: url, ... }
  const [description, setDescription]       = useState(null);
  const [phrases, setPhrases]               = useState([]);
  const [selectedPhrase, setSelectedPhrase] = useState("");
  const [customPhrase, setCustomPhrase]     = useState("");
  const [phraseFont, setPhraseFont]         = useState("rubik");
  const [phraseColor, setPhraseColor]       = useState("black");
  const [styleId, setStyleId]               = useState("kawaii");
  const [savedToGallery, setSavedToGallery] = useState(false);

  // Modals
  const [showGallery, setShowGallery]         = useState(false);
  const [showPaywall, setShowPaywall]         = useState(false);
  const [showDigital, setShowDigital]         = useState(false);
  const [showFullPreview, setShowFullPreview] = useState(false);
  const [showReferral, setShowReferral]       = useState(false);
  const [paywallTrigger, setPaywallTrigger]   = useState("credits");
  const [previewProduct, setPreviewProduct]   = useState(null);

  // Order
  const [selectedProducts, setSelectedProducts] = useState([]);

  const currentStickerUrl = styleUrls[styleId] || null;
  const currentStyle      = ALL_STYLES.find(s=>s.id===styleId) || FREE_STYLES[0];
  const currentPhrase     = customPhrase || selectedPhrase;
  const openPaywall       = trigger => { setPaywallTrigger(trigger); setShowPaywall(true); };

  // ── Camera ──────────────────────────────────────────────────────────────────
  const startCamera = useCallback(async()=>{
    try{ const s=await navigator.mediaDevices.getUserMedia({video:{facingMode:"environment"},audio:false}); streamRef.current=s; if(videoRef.current)videoRef.current.srcObject=s; }
    catch{ setCaptureMode("upload"); }
  },[]);
  const stopCamera = useCallback(()=>{ streamRef.current?.getTracks().forEach(t=>t.stop()); streamRef.current=null; },[]);
  useEffect(()=>{ if(captureMode==="camera"&&!snapPreview)startCamera(); else stopCamera(); return()=>stopCamera(); },[captureMode,snapPreview]);
  const snapPhoto   = useCallback(()=>{ const v=videoRef.current; if(!v)return; const c=document.createElement("canvas"); c.width=v.videoWidth||640; c.height=v.videoHeight||480; c.getContext("2d").drawImage(v,0,0); setSnapPreview(c.toDataURL("image/jpeg",0.92)); stopCamera(); },[stopCamera]);
  const confirmSnap = useCallback(()=>{ if(!snapPreview)return; setPetImage(snapPreview); fetch(snapPreview).then(r=>r.blob()).then(b=>setPetFile(new File([b],"snap.jpg",{type:"image/jpeg"}))); setSnapPreview(null); setCaptureMode("upload"); },[snapPreview]);
  const retakeSnap  = useCallback(()=>{ setSnapPreview(null); startCamera(); },[startCamera]);
  const handleFile  = useCallback(file=>{
    if(!file||!file.type.startsWith("image/"))return;
    setPetFile(file);
    const r=new FileReader();
    r.onload=e=>{ setPetImage(e.target.result); pixels.photoUploaded(); };
    r.readAsDataURL(file);
  },[]);

  // ── Progress simulation ──────────────────────────────────────────────────────
  const runProgress = useCallback((from,to,ms)=>{
    const steps=30, interval=ms/steps; let current=from; const inc=(to-from)/steps;
    const id=setInterval(()=>{ current=Math.min(to,current+inc+Math.random()*1.5); setLoadingProgress(Math.round(current)); if(current>=to)clearInterval(id); },interval);
    return id;
  },[]);

  // ── Generate all 3 free styles upfront ──────────────────────────────────────
  const generate = async () => {
    // Guard — block if no credits (server will also enforce this)
    if (!isPro && total <= 0) { openPaywall("out_of_credits"); return; }

    setGenError(null); setLoadingProgress(0); setStyleUrls({});

    const b64  = petImage.split(",")[1];
    const mime = petFile?.type || "image/jpeg";

    try {
      setLoadingStage("analyzing");
      const prog1 = runProgress(0, 22, 4000);
      let res;
      try {
        res = await analysePhoto(b64, mime);
      } catch(e) {
        clearInterval(prog1);
        // 402 = no credits (server-side check)
        if (e.status === 402) { openPaywall("out_of_credits"); setLoadingStage(null); return; }
        // 422 = no animal detected
        if (e.status === 422) { setGenError(e.message); setLoadingStage(null); return; }
        throw e;
      }
      clearInterval(prog1);
      const desc = res.description;  // server returns { ok: true, description: {...} }
      setDescription(desc);

      const ph     = desc?.phrases?.slice(0,3).filter(Boolean) || FALLBACK_PHRASES[0];
      const phrase = ph[0] || "My pet";
      setPhrases(ph); setSelectedPhrase(phrase); setCustomPhrase(""); setSavedToGallery(false);
      // Refresh credits display after server deduction
      onCreditsChanged?.();
      setLoadingProgress(25);

      // Generate all 3 free styles in parallel with caption baked in
      setLoadingStage("generating");
      const prog2 = runProgress(25, 92, 18000);
      const urls  = await generateAllStyles(desc, phrase, isPro);
      clearInterval(prog2);
      setLoadingProgress(100);

      const urlMap = {};
      FREE_STYLES.forEach((st,i) => { if (urls[i]) urlMap[st.id] = urls[i]; });
      setStyleUrls(urlMap);
      setStyleId("kawaii");

      await new Promise(r=>setTimeout(r,280));
      setLoadingStage(null);
      goToStep(1);
    } catch(e) {
      const fb = FALLBACK_PHRASES[Math.floor(Math.random()*FALLBACK_PHRASES.length)];
      setStyleUrls({ kawaii:petImage, comic:petImage, watercolour:petImage });
      setPhrases(fb); setSelectedPhrase(fb[0]);
      setGenError("Couldn't reach the cartoon service. Check your API keys are set in Vercel.");
      setLoadingStage(null);
      goToStep(1);
    }
  };

  // ── Regen a single style (used when caption changes or user taps "Try again") ─
  const regenStyle = async (sId, caption) => {
    if (!description) return;
    setRegenStyleIds(p => [...p, sId]);
    try {
      const url = await generateSticker(description, sId, caption || currentPhrase);
      if (url) setStyleUrls(p => ({...p, [sId]: url}));
    } catch {}
    setRegenStyleIds(p => p.filter(x => x !== sId));
  };

  const regenCurrentStyle = () => regenStyle(styleId, currentPhrase);

  // ── Regen all free styles when caption changes ───────────────────────────────
  const regenAllWithCaption = async (caption) => {
    setRegenStyleIds(FREE_STYLES.map(s=>s.id));
    const urls = await generateAllStyles(description, caption);
    const urlMap = {...styleUrls};
    FREE_STYLES.forEach((st,i) => { if (urls[i]) urlMap[st.id] = urls[i]; });
    setStyleUrls(urlMap);
    setRegenStyleIds([]);
  };

  // ── Pro style generation on demand ──────────────────────────────────────────
  const selectStyle = async (newId) => {
    setStyleId(newId);
    // Free styles are already generated — just switch
    if (!ALL_STYLES.find(s=>s.id===newId)?.proOnly) return;
    // Pro style: generate now if not already done
    if (styleUrls[newId]) return;
    await regenStyle(newId, currentPhrase);
  };

  // ── Navigation ──────────────────────────────────────────────────────────────
  const goToStep = s => {
    setStep(s);
    window.scrollTo({top:0,behavior:"smooth"});
    if (s === 2) pixels.reachedProducts();
  };

  // ── Gallery ─────────────────────────────────────────────────────────────────
  const saveToGallery = () => {
    gallery.save({ url:currentStickerUrl, styleId, phrase:currentPhrase, fontId:phraseFont, colorId:phraseColor });
    setSavedToGallery(true);
  };

  // ── Products ────────────────────────────────────────────────────────────────
  const toggleProduct = id => setSelectedProducts(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);
  const physTotal     = selectedProducts.filter(id=>id!=="vsticker").reduce((s,id)=>s+(PRODUCTS.find(p=>p.id===id)?.price||0),0);
  const hasDigital    = selectedProducts.includes("vsticker");

  // ── Reset ───────────────────────────────────────────────────────────────────
  const reset = () => {
    setStep(0); setOrderDone(false);
    setPetImage(null); setPetFile(null); setSnapPreview(null);
    setStyleUrls({}); setDescription(null);
    setPhrases([]); setSelectedPhrase(""); setCustomPhrase("");
    setPhraseFont("rubik"); setPhraseColor("black"); setStyleId("kawaii");
    setSelectedProducts([]); setGenError(null); setSavedToGallery(false);
  };

  // ── Share ───────────────────────────────────────────────────────────────────
  const sharePet = async () => {
    const msg=`My pet is now a cartoon sticker! 🐾 ${APP_DOMAIN}`;
    if(navigator.share){ try{await navigator.share({text:msg});return;}catch{} }
    try{await navigator.clipboard.writeText(msg);}catch{}
  };

  // ── Onboarding ──────────────────────────────────────────────────────────────
  if (showOnboarding) return <OnboardingScreen onStart={()=>setShowOnboarding(false)} />;

  // ── Success ─────────────────────────────────────────────────────────────────
  if (orderDone) return (
    <div style={S.app}>
      <div style={S.confettiWrap}>{["🎉","✨","🐾","💝","🌟","🎊","🐶","🐱"].map((e,i)=><span key={i} style={{...S.confetti,left:`${5+i*12}%`,animationDelay:`${i*0.15}s`,animationDuration:`${2.4+i*0.3}s`}}>{e}</span>)}</div>
      <div style={{padding:"40px 20px 60px",display:"flex",flexDirection:"column",alignItems:"center",textAlign:"center"}}>
        <div style={{fontSize:60,marginBottom:8}}>🎉</div>
        <h2 style={{...S.title,fontSize:24,marginBottom:6}}>Order placed!</h2>
        <p style={{color:"rgba(255,255,255,0.5)",fontSize:14,fontFamily:"'DynaPuff',cursive",lineHeight:1.55,maxWidth:300,marginBottom:20}}>
          Your pet is officially famous. You'll get a confirmation email in a day or two. 🐾
        </p>
        <StickerCard url={currentStickerUrl} style={currentStyle} size={190} />

        <div style={{marginTop:20,width:"100%",maxWidth:360,background:"rgba(255,133,161,0.08)",border:"1px solid rgba(255,133,161,0.2)",borderRadius:18,padding:16,textAlign:"left"}}>
          <div style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:16,color:"#fff",marginBottom:4}}>Show your pet off! 🌟</div>
          <p style={{color:"rgba(255,255,255,0.45)",fontSize:12,fontFamily:"'DynaPuff',cursive",margin:"0 0 12px",lineHeight:1.4}}>Post on Instagram or TikTok and tag #CutePawLabs</p>
          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>downloadAsPng(currentStickerUrl,!isPro)} style={{flex:1,padding:"10px",borderRadius:12,border:"none",background:"linear-gradient(135deg,#FF85A1,#FF5C8A)",color:"#fff",fontWeight:800,fontSize:12,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>📥 Save PNG</button>
            <button onClick={sharePet} style={{flex:1,padding:"10px",borderRadius:12,border:"1px solid rgba(255,255,255,0.15)",background:"rgba(255,255,255,0.06)",color:"rgba(255,255,255,0.7)",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>🔗 Share</button>
          </div>
        </div>

        <div style={{width:"100%",maxWidth:360,marginTop:10,display:"flex",flexDirection:"column",gap:10}}>
          {hasDigital&&<button onClick={()=>setShowDigital(true)} style={{...S.btnPrimary,background:"linear-gradient(135deg,#7B61FF,#5B41DF)",boxShadow:"0 8px 24px rgba(123,97,255,0.4)"}}>✨ Download Digital Sticker</button>}
          <button onClick={reset} style={S.btnSecondary}>Make another 🐾</button>
        </div>

        {!isPro&&<div onClick={()=>openPaywall("pro")} style={{marginTop:16,width:"100%",maxWidth:360,background:"linear-gradient(135deg,rgba(123,97,255,0.2),rgba(91,65,223,0.15))",border:"1px solid rgba(123,97,255,0.35)",borderRadius:18,padding:"14px 16px",cursor:"pointer",display:"flex",gap:12,alignItems:"center"}}><span style={{fontSize:26}}>⚡</span><div style={{flex:1,textAlign:"left"}}><div style={{fontWeight:700,color:"#A78BFA",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>Go Pro</div><div style={{color:"rgba(255,255,255,0.4)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Unlimited stickers, no watermark · ${PRO_PRICE}/mo</div></div><span style={{color:"#A78BFA",fontSize:18}}>→</span></div>}
      </div>
      {showDigital&&<DigitalModal stickerUrl={currentStickerUrl} isPro={isPro} onClose={()=>setShowDigital(false)} />}
      {showPaywall&&<PaywallModal trigger={paywallTrigger} daysUntilReset={daysUntilReset} onClose={()=>setShowPaywall(false)} onPurchase={p=>addCredits(p.credits)} onPro={activatePro} onReferral={()=>setShowReferral(true)} />}
      {showReferral&&<ReferralModal onClose={()=>setShowReferral(false)} onClaim={addCredits} />}
      <style>{CSS}</style>
    </div>
  );

  // ── Main app ─────────────────────────────────────────────────────────────────
  return (
    <div style={S.app}>
      {loadingStage&&!regenLoading&&<LoadingOverlay stage={loadingStage} progress={loadingProgress} />}

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"18px 16px 10px"}}>
        <div style={{display:"flex",alignItems:"center",gap:7}}>
          <span style={{fontSize:24}}>{APP_EMOJI}</span>
          <span style={{fontFamily:"'Rubik Bubbles',cursive",fontSize:22,color:"#fff"}}>{APP_NAME}</span>
          {isPro&&<span style={{background:"linear-gradient(135deg,#7B61FF,#5B41DF)",color:"#fff",fontSize:9,fontWeight:800,padding:"3px 8px",borderRadius:10,fontFamily:"'DynaPuff',cursive",letterSpacing:"0.08em"}}>PRO</span>}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <button onClick={()=>setShowReferral(true)} title="Earn free credits" style={{padding:"6px 10px",borderRadius:20,border:"1.5px solid rgba(76,184,122,0.4)",background:"rgba(76,184,122,0.1)",cursor:"pointer",fontSize:14}}>🎁</button>
          <button onClick={()=>setShowGallery(true)} style={{position:"relative",padding:"6px 10px",borderRadius:20,border:"1.5px solid rgba(255,255,255,0.15)",background:"rgba(255,255,255,0.06)",cursor:"pointer"}}>
            <span style={{fontSize:14}}>🖼️</span>
            {gallery.items.length>0&&<span style={{position:"absolute",top:-4,right:-4,background:"#FF85A1",color:"#fff",borderRadius:"50%",width:16,height:16,fontSize:9,fontWeight:800,fontFamily:"'DynaPuff',cursive",display:"flex",alignItems:"center",justifyContent:"center"}}>{gallery.items.length}</span>}
          </button>
          <CreditPill total={total} isPro={isPro} onPress={()=>openPaywall(isPro?"pro":"credits")} />
        </div>
      </div>

      <div style={{padding:"0 16px 60px",maxWidth:480,margin:"0 auto"}}>
        <StepDots step={step} />

        {/* ── STEP 0: Upload ─────────────────────────────────────────────────── */}
        {step===0&&(
          <div style={{...S.card,animation:"fadeIn 0.3s ease"}}>
            <h2 style={S.title}>Add your pet 📸</h2>
            <p style={S.subtitle}>Upload a photo and we'll turn it into 3 cartoon stickers — pick your favourite style!</p>

            <div style={{display:"flex",gap:8,marginBottom:14}}>
              {[{k:"upload",l:"📁 Upload"},{k:"camera",l:"📷 Camera"}].map(({k,l})=>(
                <button key={k} onClick={()=>{setSnapPreview(null);setCaptureMode(k);}} style={{flex:1,padding:"10px",borderRadius:12,cursor:"pointer",fontWeight:700,fontSize:13,fontFamily:"'DynaPuff',cursive",transition:"all 0.2s",
                  border:`1.5px solid ${captureMode===k?"#FF85A1":"rgba(255,255,255,0.12)"}`,
                  background:captureMode===k?"rgba(255,133,161,0.18)":"transparent",
                  color:captureMode===k?"#FF85A1":"rgba(255,255,255,0.4)"}}>
                  {l}
                </button>
              ))}
            </div>

            {captureMode==="camera"&&!snapPreview&&(
              <div style={{position:"relative",borderRadius:20,overflow:"hidden",marginBottom:12,background:"#000",minHeight:220}}>
                <video ref={videoRef} autoPlay playsInline muted style={{width:"100%",display:"block",maxHeight:270,objectFit:"cover"}} />
                <button onClick={snapPhoto} style={{position:"absolute",bottom:16,left:"50%",transform:"translateX(-50%)",width:58,height:58,borderRadius:"50%",background:"rgba(255,133,161,0.9)",border:"3px solid #fff",cursor:"pointer",fontSize:22,display:"flex",alignItems:"center",justifyContent:"center"}}>📸</button>
              </div>
            )}

            {captureMode==="camera"&&snapPreview&&(
              <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12,marginBottom:12}}>
                <img src={snapPreview} alt="preview" style={{width:140,height:140,objectFit:"cover",borderRadius:"50%",border:"3px solid #FF85A1"}} />
                <p style={{color:"rgba(255,255,255,0.6)",fontSize:13,fontFamily:"'DynaPuff',cursive",margin:0}}>Use this photo?</p>
                <div style={{display:"flex",gap:10}}>
                  <button onClick={retakeSnap} style={S.btnSecondary}>↩ Retake</button>
                  <button onClick={confirmSnap} style={S.btnPrimary}>Looks good! ✓</button>
                </div>
              </div>
            )}

            {captureMode==="upload"&&(
              <div onClick={()=>fileRef.current.click()} onDragOver={e=>{e.preventDefault();setDragOver(true);}} onDragLeave={()=>setDragOver(false)} onDrop={e=>{e.preventDefault();setDragOver(false);handleFile(e.dataTransfer.files[0]);}}
                style={{border:`2px dashed ${dragOver?"#FF85A1":"rgba(255,133,161,0.28)"}`,borderRadius:18,padding:"26px 16px",textAlign:"center",cursor:"pointer",background:dragOver?"rgba(255,133,161,0.08)":"rgba(255,133,161,0.03)",transition:"all 0.2s",marginBottom:12}}>
                {petImage
                  ? <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10}}><img src={petImage} alt="pet" style={{width:120,height:120,objectFit:"cover",borderRadius:"50%",border:"3px solid rgba(255,133,161,0.7)"}} /><span style={{color:"rgba(255,255,255,0.35)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Tap to change</span></div>
                  : <><div style={{fontSize:44,marginBottom:10}}>🐶🐱</div><div style={{color:"rgba(255,255,255,0.7)",fontWeight:600,fontSize:14,fontFamily:"'DynaPuff',cursive",marginBottom:4}}>Tap to upload</div><div style={{color:"rgba(255,255,255,0.28)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>JPG · PNG · WEBP</div></>
                }
              </div>
            )}

            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={e=>handleFile(e.target.files[0])} />

            {captureMode==="upload"&&petImage&&(
              <button onClick={generate} style={{...S.btnPrimary,width:"100%"}}>
                {isPro?"Make my sticker ✨":total>0?"Make my sticker · 1 credit":"No credits left 😿"}
              </button>
            )}

            {!isPro&&(
              <div style={{marginTop:16,background:"rgba(255,255,255,0.04)",borderRadius:12,padding:"12px 14px"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <span style={{fontSize:12,fontWeight:600,color:"rgba(255,255,255,0.65)",fontFamily:"'DynaPuff',cursive"}}>{total>0?`${total} sticker${total!==1?"s":""} left`:"No stickers left"}</span>
                  <div style={{display:"flex",gap:8}}>
                    <button onClick={()=>setShowReferral(true)} style={{fontSize:11,fontWeight:700,color:"#4CB87A",background:"transparent",border:"none",cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>🎁 Free credit</button>
                    <button onClick={()=>openPaywall("credits")} style={{fontSize:11,fontWeight:700,color:"#FF85A1",background:"transparent",border:"none",cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>Buy →</button>
                  </div>
                </div>
                <div style={{height:5,borderRadius:3,background:"rgba(255,255,255,0.08)",overflow:"hidden"}}>
                  <div style={{height:"100%",borderRadius:3,width:`${Math.min(100,(credits/FREE_CREDITS)*100)}%`,transition:"width 0.5s ease",background:credits>1?"linear-gradient(90deg,#FF85A1,#FF5C8A)":"linear-gradient(90deg,#FF6060,#FF3030)"}} />
                </div>
                <div style={{display:"flex",justifyContent:"space-between",marginTop:4}}>
                  <span style={{fontSize:9,color:"rgba(255,255,255,0.3)",fontFamily:"'DynaPuff',cursive"}}>FREE MONTHLY</span>
                  <span style={{fontSize:9,color:"rgba(255,255,255,0.3)",fontFamily:"'DynaPuff',cursive"}}>Resets in {daysUntilReset}d</span>
                </div>
              </div>
            )}
          </div>
        )}

        {/* ── STEP 1: Customise ───────────────────────────────────────────────── */}
        {step===1&&(
          <div style={{...S.card,animation:"fadeIn 0.3s ease"}}>
            <h2 style={S.title}>Your stickers! 🎨</h2>
            <p style={S.subtitle}>{description?`${description.animal} · ${description.expression} vibes · tap a style to switch instantly`:"Tap a style below to switch!"}</p>

            {genError&&<div style={{background:"rgba(255,166,0,0.1)",border:"1px solid rgba(255,166,0,0.28)",borderRadius:10,padding:"8px 12px",marginBottom:12,fontSize:11,color:"rgba(255,200,0,0.8)",fontFamily:"'DynaPuff',cursive"}}>⚠️ {genError}</div>}

            {/* Main sticker preview */}
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10,marginBottom:16}}>
              <StickerCard
                url={currentStickerUrl} style={currentStyle} size={220}
                loading={regenStyleIds.includes(styleId)}
                onClick={()=>setShowFullPreview(true)} showZoomHint
              />
              <button onClick={regenCurrentStyle} disabled={regenStyleIds.includes(styleId)||!description} style={{padding:"6px 14px",borderRadius:10,border:"1px solid rgba(255,255,255,0.15)",background:"rgba(255,255,255,0.05)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'DynaPuff',cursive",transition:"all 0.2s",color:regenStyleIds.includes(styleId)?"#FF85A1":"rgba(255,255,255,0.5)"}}>
                {regenStyleIds.includes(styleId)?"⟳ Drawing...":"🔄 Try again"}
              </button>
            </div>

            {/* Style picker with thumbnails */}
            <StylePicker
              styleUrls={styleUrls} selectedId={styleId}
              onSelect={selectStyle} isPro={isPro}
              onUnlock={()=>openPaywall("pro")}
              loadingIds={regenStyleIds}
            />

            {/* Caption / phrase editor */}
            <PhraseEditor
              phrases={phrases} selected={selectedPhrase} onSelect={setSelectedPhrase}
              custom={customPhrase} setCustom={setCustomPhrase}
              fontId={phraseFont} setFontId={setPhraseFont}
              colorId={phraseColor} setColorId={setPhraseColor}
              onRegenerate={()=>regenAllWithCaption(currentPhrase)}
            />

            <button onClick={saveToGallery} disabled={savedToGallery} style={{width:"100%",padding:"8px",borderRadius:10,transition:"all 0.3s",marginBottom:12,
              border:`1px solid ${savedToGallery?"rgba(76,184,122,0.5)":"rgba(255,255,255,0.15)"}`,
              background:savedToGallery?"rgba(76,184,122,0.12)":"rgba(255,255,255,0.05)",
              color:savedToGallery?"#4CB87A":"rgba(255,255,255,0.5)",
              fontSize:11,fontWeight:700,cursor:savedToGallery?"default":"pointer",fontFamily:"'DynaPuff',cursive"}}>
              {savedToGallery?"✓ Saved to gallery":"🖼️ Save to gallery"}
            </button>

            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>goToStep(0)} style={S.btnSecondary}>← Back</button>
              <button onClick={()=>goToStep(2)} style={{...S.btnPrimary,flex:1}}>Pick products →</button>
            </div>
          </div>
        )}

        {/* ── STEP 2: Products ────────────────────────────────────────────────── */}
        {step===2&&(
          <div style={{...S.card,animation:"fadeIn 0.3s ease"}}>
            <h2 style={S.title}>Put it on something! 🛍️</h2>
            <p style={S.subtitle}>Print-on-demand, no stock needed. Ships anywhere!</p>

            {/* Edit sticker banner */}
            <EditStickerBanner url={currentStickerUrl} style={currentStyle} onEdit={()=>goToStep(1)} />

            <div style={S.label}>DIGITAL — FREE</div>
            {PRODUCTS.filter(p=>p.digital).map(p=>(
              <div key={p.id} onClick={()=>toggleProduct(p.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"13px 14px",borderRadius:14,cursor:"pointer",marginBottom:12,transition:"all 0.2s",
                background:selectedProducts.includes(p.id)?"rgba(123,97,255,0.18)":"rgba(255,255,255,0.04)",
                border:`2px solid ${selectedProducts.includes(p.id)?"#7B61FF":"rgba(255,255,255,0.09)"}`}}>
                <span style={{fontSize:22}}>{p.emoji}</span>
                <div style={{flex:1}}><div style={{fontWeight:700,color:"#fff",fontSize:13,fontFamily:"'DynaPuff',cursive"}}>{p.name}</div><div style={{color:"rgba(255,255,255,0.35)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>{p.desc}</div></div>
                <div style={{background:"linear-gradient(135deg,#7B61FF,#5B41DF)",color:"#fff",fontWeight:800,fontSize:11,padding:"3px 10px",borderRadius:20,fontFamily:"'DynaPuff',cursive"}}>FREE</div>
              </div>
            ))}

            <div style={S.label}>PHYSICAL PRODUCTS</div>
            <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
              {PRODUCTS.filter(p=>!p.digital).map(p=>{
                const sel=selectedProducts.includes(p.id);
                return (
                  <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",borderRadius:14,transition:"all 0.2s",
                    background:sel?"rgba(255,133,161,0.12)":"rgba(255,255,255,0.04)",
                    border:`2px solid ${sel?"#FF85A1":"rgba(255,255,255,0.08)"}`}}>
                    <div onClick={()=>toggleProduct(p.id)} style={{display:"flex",alignItems:"center",gap:10,flex:1,cursor:"pointer"}}>
                      <div style={{width:44,height:44,borderRadius:10,background:"rgba(255,255,255,0.08)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,fontSize:20}}>{p.emoji}</div>
                      <div style={{flex:1}}>
                        <div style={{fontWeight:700,color:"#fff",fontSize:12,fontFamily:"'DynaPuff',cursive"}}>{p.name}</div>
                        <div style={{color:"rgba(255,255,255,0.3)",fontSize:10,fontFamily:"'DynaPuff',cursive"}}>{p.desc}</div>
                      </div>
                      <div style={{color:sel?"#FF85A1":"rgba(255,255,255,0.4)",fontWeight:700,fontSize:13,fontFamily:"'DynaPuff',cursive"}}>${p.price}</div>
                    </div>
                    <button onClick={e=>{e.stopPropagation();setPreviewProduct(p);}} style={{fontSize:10,color:"rgba(123,97,255,0.7)",background:"transparent",border:"1px solid rgba(123,97,255,0.3)",borderRadius:8,padding:"3px 8px",cursor:"pointer",fontFamily:"'DynaPuff',cursive",fontWeight:700,flexShrink:0}}>👁</button>
                  </div>
                );
              })}
            </div>

            {selectedProducts.length>0&&(
              <div style={{background:"rgba(76,184,122,0.1)",border:"1px solid rgba(76,184,122,0.28)",borderRadius:12,padding:"10px 14px",marginBottom:12,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div>
                  <div style={{color:"rgba(255,255,255,0.55)",fontSize:12,fontFamily:"'DynaPuff',cursive"}}>{selectedProducts.length} item{selectedProducts.length>1?"s":""} selected</div>
                  {hasDigital&&physTotal===0&&<div style={{color:"#7B61FF",fontSize:11,fontFamily:"'DynaPuff',cursive",marginTop:2}}>Digital only, no address needed</div>}
                </div>
                <span style={{color:"#4CB87A",fontWeight:800,fontSize:20,fontFamily:"'Rubik Bubbles',cursive"}}>{physTotal>0?`$${physTotal.toFixed(2)}`:"Free!"}</span>
              </div>
            )}

            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>goToStep(1)} style={S.btnSecondary}>← Back</button>
              <button onClick={()=>goToStep(3)} disabled={!selectedProducts.length} style={{...S.btnPrimary,flex:1,opacity:!selectedProducts.length?0.45:1}}>Review →</button>
            </div>
          </div>
        )}

        {/* ── STEP 3: Checkout ────────────────────────────────────────────────── */}
        {step===3&&(
          <div style={{...S.card,animation:"fadeIn 0.3s ease"}}>
            <h2 style={S.title}>Almost there! 🎁</h2>

            {/* Edit sticker banner */}
            <EditStickerBanner url={currentStickerUrl} style={currentStyle} onEdit={()=>goToStep(1)} />

            <div style={{display:"flex",gap:14,marginBottom:18,alignItems:"flex-start"}}>
              <StickerCard url={currentStickerUrl} style={currentStyle} size={90} />
              <div style={{flex:1}}>
                {selectedProducts.map(id=>{const p=PRODUCTS.find(x=>x.id===id);return p?(
                  <div key={id} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid rgba(255,255,255,0.06)",fontFamily:"'DynaPuff',cursive"}}>
                    <span style={{color:"rgba(255,255,255,0.6)",fontSize:12}}>{p.emoji} {p.name}</span>
                    <span style={{color:p.digital?"#7B61FF":"#fff",fontWeight:700,fontSize:12}}>{p.digital?"FREE":`$${p.price.toFixed(2)}`}</span>
                  </div>
                ):null;})}
                <div style={{display:"flex",justifyContent:"space-between",paddingTop:8}}>
                  <span style={{color:"rgba(255,255,255,0.3)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Free shipping ✓</span>
                  <span style={{color:"#4CB87A",fontWeight:800,fontSize:18,fontFamily:"'Rubik Bubbles',cursive"}}>{physTotal>0?`$${physTotal.toFixed(2)}`:"Free!"}</span>
                </div>
              </div>
            </div>

            {physTotal>0&&(
              <>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
                  <div><input type="text" placeholder="Your name" value={form.fields.name} onChange={e=>form.set("name",e.target.value)} onBlur={()=>form.touch("name")} style={{...S.input,margin:0,borderColor:form.touched.name&&form.errors.name?"rgba(255,100,100,0.6)":undefined}} />{form.touched.name&&form.errors.name&&<div style={S.fieldErr}>⚠ {form.errors.name}</div>}</div>
                  <div><input type="email" placeholder="Email" value={form.fields.email} onChange={e=>form.set("email",e.target.value)} onBlur={()=>form.touch("email")} style={{...S.input,margin:0,borderColor:form.touched.email&&form.errors.email?"rgba(255,100,100,0.6)":undefined}} />{form.touched.email&&form.errors.email&&<div style={S.fieldErr}>⚠ {form.errors.email}</div>}</div>
                </div>
                <div style={{marginBottom:8}}><input type="text" placeholder="Street address" value={form.fields.address} onChange={e=>form.set("address",e.target.value)} onBlur={()=>form.touch("address")} style={{...S.input,margin:0,borderColor:form.touched.address&&form.errors.address?"rgba(255,100,100,0.6)":undefined}} />{form.touched.address&&form.errors.address&&<div style={S.fieldErr}>⚠ {form.errors.address}</div>}</div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 2fr",gap:8,marginBottom:8}}>
                  <div><input type="text" placeholder="Postcode" value={form.fields.postcode} onChange={e=>form.set("postcode",e.target.value)} onBlur={()=>form.touch("postcode")} style={{...S.input,margin:0,borderColor:form.touched.postcode&&form.errors.postcode?"rgba(255,100,100,0.6)":undefined}} />{form.touched.postcode&&form.errors.postcode&&<div style={S.fieldErr}>⚠ {form.errors.postcode}</div>}</div>
                  <div><input type="text" placeholder="City" value={form.fields.city} onChange={e=>form.set("city",e.target.value)} onBlur={()=>form.touch("city")} style={{...S.input,margin:0,borderColor:form.touched.city&&form.errors.city?"rgba(255,100,100,0.6)":undefined}} />{form.touched.city&&form.errors.city&&<div style={S.fieldErr}>⚠ {form.errors.city}</div>}</div>
                </div>
              </>
            )}

            {hasDigital&&physTotal===0&&<div style={{background:"rgba(123,97,255,0.1)",border:"1px solid rgba(123,97,255,0.28)",borderRadius:12,padding:"12px 14px",fontFamily:"'DynaPuff',cursive",marginBottom:12}}><div style={{fontWeight:700,color:"#7B61FF",fontSize:13,marginBottom:3}}>✨ Digital only</div><div style={{color:"rgba(255,255,255,0.45)",fontSize:12}}>No address needed, download starts right away.</div></div>}
            <div style={{background:"rgba(255,255,255,0.04)",borderRadius:11,padding:"9px 12px",margin:"0 0 12px",display:"flex",gap:8,alignItems:"center"}}><span>🔒</span><span style={{color:"rgba(255,255,255,0.33)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Secure payment via Stripe · Ships in 5 to 7 days</span></div>

            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>goToStep(2)} style={S.btnSecondary}>← Back</button>
              <button onClick={()=>{if(physTotal>0&&!form.isValid){form.touchAll();return;}setOrderDone(true); pixels.purchase(physTotal, selectedProducts); window.scrollTo({top:0,behavior:"smooth"});}} style={{...S.btnPrimary,flex:1,background:"linear-gradient(135deg,#4CB87A,#3AA869)",boxShadow:"0 8px 22px rgba(76,184,122,0.4)"}}>
                🎉 Place order{physTotal>0?` · $${physTotal.toFixed(2)}`:" · Free!"}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      {showGallery&&<GalleryModal items={gallery.items} onClose={()=>setShowGallery(false)} onDelete={gallery.remove} onUse={item=>{setStyleUrls(p=>({...p,[item.styleId||"kawaii"]:item.url}));setStyleId(item.styleId||"kawaii");setSelectedPhrase(item.phrase||"");setCustomPhrase("");setPhraseFont(item.fontId||"rubik");setPhraseColor(item.colorId||"black");goToStep(1);}} />}
      {showPaywall&&<PaywallModal trigger={paywallTrigger} daysUntilReset={daysUntilReset} onClose={()=>setShowPaywall(false)} onPurchase={p=>{ onCreditsChanged?.(); }} onPro={()=>{ onCreditsChanged?.(); }} onReferral={()=>{setShowPaywall(false);setShowReferral(true);}} />}
      {showDigital&&currentStickerUrl&&<DigitalModal stickerUrl={currentStickerUrl} isPro={isPro} onClose={()=>setShowDigital(false)} />}
      {previewProduct&&currentStickerUrl&&<MockupModal product={previewProduct} stickerUrl={currentStickerUrl} onClose={()=>setPreviewProduct(null)} />}
      {showReferral&&<ReferralModal deviceId={deviceId} onClose={()=>setShowReferral(false)} onClaim={()=>onCreditsChanged?.()} />}

      {/* Full screen preview */}
      {showFullPreview&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.93)",backdropFilter:"blur(20px)",zIndex:700,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:20}} onClick={()=>setShowFullPreview(false)}>
          <StickerCard url={currentStickerUrl} style={currentStyle} size={290} />
          <div style={{display:"flex",gap:12}}>
            <button onClick={e=>{e.stopPropagation();downloadAsPng(currentStickerUrl,!isPro);}} style={{padding:"10px 20px",borderRadius:12,border:"none",background:"linear-gradient(135deg,#FF85A1,#FF5C8A)",color:"#fff",fontWeight:800,fontSize:13,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>📥 Save PNG</button>
            <button onClick={()=>setShowFullPreview(false)} style={{padding:"10px 20px",borderRadius:12,border:"1px solid rgba(255,255,255,0.15)",background:"rgba(255,255,255,0.06)",color:"rgba(255,255,255,0.6)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"'DynaPuff',cursive"}}>Close</button>
          </div>
          <span style={{color:"rgba(255,255,255,0.2)",fontSize:11,fontFamily:"'DynaPuff',cursive"}}>Tap anywhere to close</span>
        </div>
      )}

      <style>{CSS}</style>
    </div>
  );
}

// ─── STYLES ───────────────────────────────────────────────────────────────────

const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Rubik+Bubbles&family=DynaPuff:wght@400;500;600;700&display=swap');
  * { box-sizing: border-box; }
  body { margin:0; -webkit-tap-highlight-color:transparent; background:#0f0620; }
  input::placeholder { color: rgba(255,255,255,0.2); }
  input:focus { border-color: rgba(255,133,161,0.5) !important; box-shadow: 0 0 0 3px rgba(255,133,161,0.12); outline:none; }
  button:active { opacity:0.82; transform:scale(0.97); }
  ::-webkit-scrollbar { width:0; height:0; }
  @keyframes spin         { to { transform:rotate(360deg); } }
  @keyframes pulse        { 0%,100%{opacity:0.4;transform:scale(0.9)} 50%{opacity:1;transform:scale(1.1)} }
  @keyframes confettiFall { 0%{transform:translateY(-20px) rotate(0deg);opacity:1} 100%{transform:translateY(110vh) rotate(400deg);opacity:0} }
  @keyframes fadeIn       { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
`;

